import re
import json
from elasticsearch import Elasticsearch
from flask import Flask, request, jsonify

app = Flask(__name__)

# Elasticsearch client configuration
es = Elasticsearch(
    ['http://localhost:9200'],
    timeout=30,
    max_retries=3,
    retry_on_timeout=True
)

# Allowlist of permitted aggregation script operations
ALLOWED_SCRIPT_OPERATIONS = {
    'sum', 'avg', 'min', 'max', 'count', 'value_count',
    'cardinality', 'stats', 'extended_stats', 'percentiles',
    'terms', 'date_histogram', 'histogram', 'range'
}

# Allowlist of permitted field names pattern
ALLOWED_FIELD_PATTERN = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_.]*$')

# Blocklist of dangerous script patterns that could lead to injection or RCE
DANGEROUS_PATTERNS = [
    r'Runtime',
    r'ProcessBuilder',
    r'getRuntime',
    r'exec\s*\(',
    r'System\.',
    r'Thread\.',
    r'Class\.',
    r'forName',
    r'getClass',
    r'java\.',
    r'javax\.',
    r'import\s',
    r'reflect',
    r'invoke',
    r'newInstance',
    r'getMethod',
    r'getDeclaredMethod',
    r'File\s*\(',
    r'FileWriter',
    r'FileReader',
    r'Socket',
    r'URL\s*\(',
    r'HttpURLConnection',
    r'ScriptEngine',
    r'GroovyShell',
    r'GroovyClassLoader',
    r'evaluate',
    r'sleep\s*\(',
    r'wait\s*\(',
    r'notify',
    r'exit\s*\(',
    r'halt\s*\(',
    r'delete',
    r'_index\.',
    r'_source\.',  # Prevent direct source access manipulation
    r'ctx\._source',  # Prevent document modification
]

# Allowed Painless script patterns for aggregations
ALLOWED_PAINLESS_PATTERNS = [
    r"doc\['[a-zA-Z_][a-zA-Z0-9_.]*'\]\.value",
    r"doc\['[a-zA-Z_][a-zA-Z0-9_.]*'\]\.values",
    r"doc\['[a-zA-Z_][a-zA-Z0-9_.]*'\]\.size\(\)",
    r"doc\['[a-zA-Z_][a-zA-Z0-9_.]*'\]\.empty",
    r"doc\['[a-zA-Z_][a-zA-Z0-9_.]*'\]\.lat",
    r"doc\['[a-zA-Z_][a-zA-Z0-9_.]*'\]\.lon",
    r"params\.[a-zA-Z_][a-zA-Z0-9_]*",
    r"_value",
    r"_score",
]

MAX_SCRIPT_LENGTH = 500


def validate_script(script_source):
    """
    Validate a Painless script to ensure it only contains safe operations.
    Returns (is_valid, error_message).
    """
    if not isinstance(script_source, str):
        return False, "Script must be a string"

    if len(script_source) > MAX_SCRIPT_LENGTH:
        return False, f"Script exceeds maximum length of {MAX_SCRIPT_LENGTH} characters"

    if not script_source.strip():
        return False, "Script cannot be empty"

    # Check for dangerous patterns
    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, script_source, re.IGNORECASE):
            return False, f"Script contains disallowed pattern: {pattern}"

    return True, None


def validate_field_name(field_name):
    """Validate that a field name matches the allowed pattern."""
    if not isinstance(field_name, str):
        return False
    if len(field_name) > 100:
        return False
    return bool(ALLOWED_FIELD_PATTERN.match(field_name))


def validate_index_name(index_name):
    """Validate the index name to prevent injection."""
    if not isinstance(index_name, str):
        return False
    if len(index_name) > 255:
        return False
    # Index names should be lowercase alphanumeric with hyphens, underscores, dots
    pattern = re.compile(r'^[a-z0-9][a-z0-9_.\-*]*$')
    return bool(pattern.match(index_name))


def validate_params(params):
    """Validate script parameters - only allow primitive types."""
    if params is None:
        return True, None
    if not isinstance(params, dict):
        return False, "Params must be a dictionary"
    for key, value in params.items():
        if not isinstance(key, str) or not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', key):
            return False, f"Invalid parameter name: {key}"
        if not isinstance(value, (int, float, str, bool)):
            return False, f"Parameter '{key}' must be a primitive type (int, float, str, bool)"
        if isinstance(value, str) and len(value) > 200:
            return False, f"Parameter '{key}' string value too long"
    return True, None


def validate_aggregation_type(agg_type):
    """Validate that the aggregation type is in the allowlist."""
    return agg_type in ALLOWED_SCRIPT_OPERATIONS


def build_scripted_aggregation(agg_name, agg_type, script_source, params=None, field=None):
    """
    Build a safe Elasticsearch scripted aggregation using stored scripts
    or validated inline Painless scripts.
    """
    agg_body = {}

    if agg_type in ('sum', 'avg', 'min', 'max', 'value_count', 'stats',
                     'extended_stats', 'percentiles', 'cardinality'):
        agg_config = {}
        if script_source:
            script_def = {
                "lang": "painless",
                "source": script_source
            }
            if params:
                script_def["params"] = params
            agg_config["script"] = script_def
        elif field:
            agg_config["field"] = field

        agg_body = {
            agg_name: {
                agg_type: agg_config
            }
        }
    elif agg_type == 'terms':
        agg_config = {"size": 10}  # Default size
        if script_source:
            script_def = {
                "lang": "painless",
                "source": script_source
            }
            if params:
                script_def["params"] = params
            agg_config["script"] = script_def
        elif field:
            agg_config["field"] = field

        agg_body = {
            agg_name: {
                agg_type: agg_config
            }
        }
    else:
        return None

    return agg_body


@app.route('/api/aggregate', methods=['POST'])
def execute_aggregation():
    """
    Execute a scripted aggregation against Elasticsearch.

    Expected JSON body:
    {
        "index": "my-index",
        "agg_name": "my_aggregation",
        "agg_type": "sum",  # Must be in ALLOWED_SCRIPT_OPERATIONS
        "script": "doc['price'].value * params.factor",
        "params": {"factor": 1.2},
        "query": {"match_all": {}},  # Optional query filter
        "size": 0  # Optional, defaults to 0 for aggregation-only
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        # Extract and validate index
        index = data.get('index')
        if not index or not validate_index_name(index):
            return jsonify({"error": "Invalid or missing index name"}), 400

        # Extract and validate aggregation type
        agg_type = data.get('agg_type')
        if not agg_type or not validate_aggregation_type(agg_type):
            return jsonify({
                "error": f"Invalid aggregation type. Allowed types: {sorted(ALLOWED_SCRIPT_OPERATIONS)}"
            }), 400

        # Extract and validate aggregation name
        agg_name = data.get('agg_name', 'result')
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', agg_name):
            return jsonify({"error": "Invalid aggregation name"}), 400

        # Extract script (optional - can use field instead)
        script_source = data.get('script')
        field = data.get('field')

        if script_source:
            # Validate the script for safety
            is_valid, error_msg = validate_script(script_source)
            if not is_valid:
                return jsonify({"error": f"Script validation failed: {error_msg}"}), 400
        elif field:
            if not validate_field_name(field):
                return jsonify({"error": "Invalid field name"}), 400
        else:
            return jsonify({"error": "Either 'script' or 'field' must be provided"}), 400

        # Validate params
        params = data.get('params')
        params_valid, params_error = validate_params(params)
        if not params_valid:
            return jsonify({"error": f"Parameter validation failed: {params_error}"}), 400

        # Build the aggregation
        agg_body = build_scripted_aggregation(
            agg_name=agg_name,
            agg_type=agg_type,
            script_source=script_source,
            params=params,
            field=field
        )

        if agg_body is None:
            return jsonify({"error": "Failed to build aggregation"}), 400

        # Build the search body
        search_body = {
            "size": 0,  # We only want aggregation results
            "aggs": agg_body
        }

        # Add optional query filter (validated)
        query = data.get('query')
        if query:
            if not isinstance(query, dict):
                return jsonify({"error": "Query must be a dictionary"}), 400
            search_body["query"] = query

        # Execute the search with aggregation
        result = es.search(
            index=index,
            body=search_body,
            request_timeout=30
        )

        # Return aggregation results
        aggregations = result.get('aggregations', {})
        return jsonify({
            "success": True,
            "total_hits": result['hits']['total']['value'] if isinstance(result['hits']['total'], dict) else result['hits']['total'],
            "aggregations": aggregations
        })

    except json.JSONDecodeError:
        return jsonify({"error": "Invalid JSON in request body"}), 400
    except Exception as e:
        # Log the full error server-side but return a generic message
        app.logger.error(f"Aggregation error: {str(e)}")
        return jsonify({"error": "An error occurred while executing the aggregation"}), 500


@app.route('/api/stored-script', methods=['POST'])
def create_stored_script():
    """
    Create a stored script in Elasticsearch (admin only).
    Stored scripts are pre-validated and safer than inline scripts.

    Expected JSON body:
    {
        "script_id": "calculate_revenue",
        "script": "doc['price'].value * doc['quantity'].value",
        "params_schema": {"description": "Calculates revenue from price and quantity"}
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        script_id = data.get('script_id')
        if not script_id or not re.match(r'^[a-zA-Z_][a-zA-Z0-9_-]*$', script_id):
            return jsonify({"error": "Invalid script ID"}), 400

        if len(script_id) > 100:
            return jsonify({"error": "Script ID too long"}), 400

        script_source = data.get('script')
        if not script_source:
            return jsonify({"error": "Script source is required"}), 400

        # Validate the script
        is_valid, error_msg = validate_script(script_source)
        if not is_valid:
            return jsonify({"error": f"Script validation failed: {error_msg}"}), 400

        # Store the script in Elasticsearch
        es.put_script(
            id=script_id,
            body={
                "script": {
                    "lang": "painless",
                    "source": script_source
                }
            }
        )

        return jsonify({
            "success": True,
            "message": f"Stored script '{script_id}' created successfully"
        })

    except Exception as e:
        app.logger.error(f"Stored script creation error: {str(e)}")
        return jsonify({"error": "An error occurred while creating the stored script"}), 500


